    "export-control-so": {
      "label": "c97467_export_control_so.js",
      "section": "Enhancement-97467(Export Control and Approval)",
      "project": "Export Control and Approval",
      "path": "Projects-Crowe Howarth/Internship Capstone-I/Billable Projects/Krayden/Enhancement-97467(Export Control and Approval)/New/src/FileCabinet/SuiteScripts/c97467_export_control_so.js",
      "language": "js",
      "code": "/**\r\n * @NApiVersion 2.x\r\n * @NScriptType ClientScript\r\n */\r\n\r\ndefine(['N/query'], function (query) {\r\n\r\n    function fieldChanged(context) {\r\n        if (context.sublistId !== 'item' || context.fieldId !== 'item') {\r\n            return;\r\n        }\r\n\r\n        console.log(\"Field Changed Triggered!\");\r\n\r\n        var currentRecord = context.currentRecord;\r\n        var customerId = currentRecord.getValue({ fieldId: 'entity' });\r\n        var itemId = currentRecord.getCurrentSublistValue({\r\n            sublistId: 'item',\r\n            fieldId: 'item'\r\n        });\r\n\r\n        if (!itemId || !customerId) {\r\n            console.log(\"Customer or Item not selected.\");\r\n            return;\r\n        }\r\n\r\n        try {\r\n            var itemQuery = query.runSuiteQL({\r\n                query:\r\n                    \"SELECT i.custitem_94405 AS is_export_controlled, \" +\r\n                    \"       i.custitem_94406_ear99 AS is_ear99 \" +\r\n                    \"FROM item i \" +\r\n                    \"WHERE i.id = ?\",\r\n                params: [itemId]\r\n            });\r\n            console.log(\"itemQuery\", itemQuery);\r\n\r\n            if (!itemQuery || itemQuery.results.length === 0) {\r\n                console.log(\"Item not found in query.\");\r\n                return;\r\n            }\r\n\r\n            var itemRow = itemQuery.results[0].asMap();\r\n            var isExportControlled = itemRow.is_export_controlled === 'T' || itemRow.is_export_controlled === true;\r\n            var isEar99 = itemRow.is_ear99 === 'T' || itemRow.is_ear99 === true;\r\n            console.log(\"itemRow: \" + itemRow);\r\n            console.log(\"isExportControlled: \" + isExportControlled);\r\n            console.log(\"isEar99: \" + isEar99);\r\n\r\n            if (isExportControlled && !isEar99) {\r\n                console.log(\"Restricted item detected. Checking approval...\");\r\n\r\n                var approvalQuery = query.runSuiteQL({\r\n                    query:\r\n                        \"SELECT id \" +\r\n                        \"FROM customrecord_c97467 \" +\r\n                        \"WHERE custrecord_97467_item = ? \" +\r\n                        \"  AND custrecord_97467_customer = ? \" +\r\n                        \"  AND custrecord_97467_expiration >= CURRENT_DATE \" +\r\n                        \"  AND isinactive = 'F'\",\r\n                    params: [itemId, customerId]\r\n                });\r\n                console.log(\"approvalQuery\", approvalQuery);\r\n\r\n                if (!approvalQuery || approvalQuery.results.length === 0) {\r\n                    alert('This customer is not approved to purchase the restricted item.');\r\n                    currentRecord.setCurrentSublistValue({\r\n                        sublistId: 'item',\r\n                        fieldId: 'item',\r\n                        value: null,\r\n                        ignoreFieldChange: true\r\n                    });\r\n                }\r\n            }\r\n        }\r\n        catch (e) {\r\n            console.log(\"Error in fieldChanged: \" + e.message);\r\n        }\r\n    }\r\n\r\n    return {\r\n        fieldChanged: fieldChanged\r\n    };\r\n});\r\n"
    },
    "export-control-if": {
      "label": "c97467_export_control_if.js",
      "section": "Enhancement-97467(Export Control and Approval)",
      "project": "Export Control and Approval",
      "path": "Projects-Crowe Howarth/Internship Capstone-I/Billable Projects/Krayden/Enhancement-97467(Export Control and Approval)/New/src/FileCabinet/SuiteScripts/c97467_export_control_if.js",
      "language": "js",
      "code": "/**\r\n * @NApiVersion 2.x\r\n * @NScriptType UserEventScript\r\n */\r\n\r\ndefine(['N/record', 'N/query', 'N/log'], function (record, query, log) {\r\n\r\n    function beforeSubmit(context) {\r\n        try {\r\n            if (context.type !== context.UserEventType.CREATE && context.type !== context.UserEventType.EDIT) {\r\n                return;\r\n            }\r\n\r\n            var fulfillment = context.newRecord;\r\n            var salesOrderId = fulfillment.getValue('createdfrom');\r\n            log.debug(\"fulfillment\", fulfillment);\r\n            log.debug(\"salesOrderId\", salesOrderId);\r\n\r\n\r\n            if (!salesOrderId) {\r\n                log.debug('Skipping', 'No source Sales Order');\r\n                return;\r\n            }\r\n\r\n            var customerQuery = query.runSuiteQL({\r\n                query: \"SELECT entity FROM transaction WHERE id = ?\",\r\n                params: [salesOrderId]\r\n            });\r\n            var customerId = customerQuery.results[0].asMap().entity;\r\n            /* Manu's Note: We need Customer ID from Item Fulfilment Record, but it is not present there,\r\n              so we have options to either of them: search, load, query. The most optimised is using query Module. */\r\n\r\n            var lineCount = fulfillment.getLineCount({ sublistId: 'item' });\r\n            log.debug(\"customerId\", customerId);\r\n            log.debug(\"lineCount\", lineCount);\r\n\r\n\r\n\r\n            for (var i = 0; i < lineCount; i++) {\r\n                var itemId = fulfillment.getSublistValue({\r\n                    sublistId: 'item',\r\n                    fieldId: 'item',\r\n                    line: i\r\n                });\r\n\r\n                log.debug(\"itemId\", itemId);\r\n                if (!itemId) continue;\r\n\r\n\r\n                var itemQuery = query.runSuiteQL({\r\n                    query:\r\n                        \"SELECT i.custitem_94405 AS is_export_controlled, \" +\r\n                        \"       i.custitem_94406_ear99 AS is_ear99 \" +\r\n                        \"FROM item i \" +\r\n                        \"WHERE i.id = ?\",\r\n                    params: [itemId]\r\n                });\r\n                log.debug(\"itemQuery\", itemQuery);\r\n\r\n\r\n                var itemRow = itemQuery.results[0].asMap();\r\n                var isExportControlled = itemRow.is_export_controlled === 'T' || itemRow.is_export_controlled === true;\r\n                var isEar99 = itemRow.is_ear99 === 'T' || itemRow.is_ear99 === true;\r\n                log.debug(\"itemRow: \" + itemRow);\r\n                log.debug(\"isExportControlled: \" + isExportControlled);\r\n                log.debug(\"isEar99: \" + isEar99);\r\n\r\n                if (isExportControlled && !isEar99) {\r\n                    log.debug('Restricted item found', 'Checking approval for Item: ' + itemId + ', Customer ID: ' + customerId);\r\n\r\n\r\n                    var approvalQuery = query.runSuiteQL({\r\n                        query:\r\n                            \"SELECT id \" +\r\n                            \"FROM customrecord_c97467 \" +\r\n                            \"WHERE custrecord_97467_item = ? \" +\r\n                            \"  AND custrecord_97467_customer = ? \" +\r\n                            \"  AND custrecord_97467_expiration >= CURRENT_DATE \" +\r\n                            \"  AND isinactive = 'F'\",\r\n                        params: [itemId, customerId]\r\n                    });\r\n                    log.debug(\"approvalQuery\", approvalQuery);\r\n\r\n\r\n                    if (!approvalQuery || approvalQuery.results.length === 0) {\r\n                        throw Error('Item Fulfillment blocked: Customer is no longer approved to receive restricted item: ' + itemId);\r\n                    }\r\n                }\r\n            }\r\n        }\r\n        catch (error) {\r\n            log.error(\"Error\", e.message);\r\n        }\r\n    }\r\n\r\n    return {\r\n        beforeSubmit: beforeSubmit\r\n    };\r\n});\r\n"
    }
